import React from 'react';
import { DragDropContext, Droppable, Draggable } from 'react-beautiful-dnd';
import './TeamDisplay.css';

const TeamDisplay = ({ teams, showDetails, calculateAverageRating, handleDragEnd }) => {
  return (
    <DragDropContext onDragEnd={handleDragEnd}>
      <div className="teams-container">
        {teams.map((team, index) => (
          <Droppable droppableId={`team-${index}`} key={index}>
            {(provided) => (
              <div
                ref={provided.innerRef}
                {...provided.droppableProps}
                className="team-card"
              >
                <h4>
                  Team {index + 1}: {team.length} players
                </h4>
                <h4>Average Rating: {calculateAverageRating(team).toFixed(2)}</h4>
                <table className="table table-striped table-bordered">
                  <thead>
                    <tr>
                      {showDetails && <th></th>}
                      {showDetails && <th>Rating</th>}
                    </tr>
                  </thead>
                  <tbody>
                    {team.map((player, playerIndex) => (
                      <Draggable
                        key={player.id}
                        draggableId={player.id}
                        index={playerIndex}
                      >
                        {(provided) => (
                          <tr
                            ref={provided.innerRef}
                            {...provided.draggableProps}
                            {...provided.dragHandleProps}
                          >
                            <td>{player.name}</td>
                            {showDetails && <td>{player.rating}</td>}
                          </tr>
                        )}
                      </Draggable>
                    ))}
                    {provided.placeholder}
                  </tbody>
                </table>
              </div>
            )}
          </Droppable>
        ))}
      </div>
    </DragDropContext>
  );
};

export default TeamDisplay;
